/**
 * Mock File System
 */
const mockFileSystem = {
  "example.txt": [
    "This is the first line of the file.",
    "This is the second line.",
    "It demonstrates the requested format.",
    "Each line is prefixed by its number.",
    "A colon separates the number from the content.",
    "This makes it easy to identify lines.",
    "It is much faster to read than a JSON array.",
    "You can use these numbers for patching.",
    "Almost at the end of the example.",
    "This is the tenth line."
  ]
};

/**
 * Mock read_file function
 * 
 * @param {string} file_path - The path to the file.
 * @returns {string} - The plain text content with line numbers.
 */
function read_file(file_path) {
  const lines = mockFileSystem[file_path];

  if (!lines) {
    throw new Error('File not found.');
  }

  const formattedOutput = lines
    .map((content, index) => `${index + 1}: ${content}`)
    .join('\n');

  return formattedOutput;
}

